    public function authenticate($url) {
        $this->check_required_credentials();
        if (($this->clients !== null) && (is_array($this->clients) && array_key_exists($url, $this->clients))) {
            return;
        }
        $timestamp = $this->nonce();
        $payload = (string) $timestamp . '/v3/ws/private';
        $signature = $this->hmac($this->encode($payload), $this->encode($this->secret), 'sha256', 'base64');
        $originalHeaders = $this->options['ws']['options']['headers'];
        $userAgent = $this->safe_string($originalHeaders, 'User-Agent', 'ccxt');
        $extendedOptions = array(
            'ws' => array(
                'options' => array(
                    'headers' => array(
                        'User-Agent' => $userAgent,
                        'ACCESS-KEY' => $this->apiKey,
                        'ACCESS-SIGN' => $signature,
                        'ACCESS-PASSPHRASE' => $this->password,
                        'ACCESS-TIMESTAMP' => $this->number_to_string($timestamp),
                    ),
                ),
            ),
        );
        $this->extend_exchange_options($extendedOptions);
        // instantiate client
        $this->client($url);
        // return headers to original state
        $defaultOptions = array(
            'ws' => array(
                'options' => array(
                    'headers' => array(
                        'User-Agent' => $userAgent,
                    ),
                ),
            ),
        );
        $this->extend_exchange_options($defaultOptions);
    }

