             */
            Async\await($this->load_markets());
            $symbols = $this->market_symbols($symbols, null, false, true);
            $firstMarket = $this->get_market_from_symbols($symbols);
            $isContract = $firstMarket['contract'];
            $topic = 'ticker';
            $messageHashes = array();
            $channels = array();
            for ($i = 0; $i < count($symbols); $i++) {
                $symbol = $symbols[$i];
