    }

    public function parse_ws_ticker(array $ticker, ?array $market = null): array {
        //
        //     {
        //         "p" => "-18.93",
        //         "P" => "-0.008592",
        //         "w" => "2192.40298388",
        //         "c" => "2184.20",
        //         "o" => "2203.13",
