    public function handle_ohlcv(Client $client, $message) {
        //
        //     {
        //         e => 'kline',
        //         E => 1776095535012,
        //         s => 'ETHUSDT',
        //         p => 'LAST_PRICE',
        //         d => array(
        //             {
        //                 t => 1776092400000,
        //                 T => 1776096000000,
        //                 s => 'ETHUSDT',
        //                 $i => '1h',
        //                 o => '2234.18',
        //                 c => '2205.15',
        //                 h => '2236.43',
        //                 l => '2199.53',
        //                 v => '12505.60574',
        //                 n => 3381,
        //                 q => '27682528.6655305',
        //                 V => '6420.47929',
        //                 Q => '14213680.1906424'
        //             }
        //         )
        //     }
        //
        $market = $this->get_market_from_client_and_message($client, $message);
        $symbol = $market['symbol'];
        if (!(is_array($this->ohlcvs) && array_key_exists($symbol, $this->ohlcvs))) {
            $this->ohlcvs[$symbol] = array();
        }
        $data = $this->safe_list($message, 'd', array());
        $firstEntry = $this->safe_dict($data, 0, array());
        $interval = $this->safe_string($firstEntry, 'i');
        $timeframe = $this->find_timeframe($interval);
        if (!(is_array($this->ohlcvs[$symbol]) && array_key_exists($timeframe, $this->ohlcvs[$symbol]))) {
            $limit = $this->safe_integer($this->options, 'OHLCVLimit', 1000);
            $this->ohlcvs[$symbol][$timeframe] = new ArrayCacheByTimestamp ($limit);
        }
        $stored = $this->ohlcvs[$symbol][$timeframe];
        for ($i = 0; $i < count($data); $i++) {
            $entry = $this->safe_dict($data, $i, array());
            $parsed = $this->parse_ws_ohlcv($entry);
            $stored->append ($parsed);
        }
        $messageHash = 'ohlcv::' . $symbol . '::' . $timeframe;
        $resolveData = array( $symbol, $timeframe, $stored );
        $client->resolve ($resolveData, $messageHash);
    }

    public function parse_ws_ohlcv($ohlcv, $market = null): array {
        //
        //     {
        //         t => 1776092400000,
        //         T => 1776096000000,
        //         s => 'ETHUSDT',
        //         i => '1h',
        //         o => '2234.18',
        //         c => '2205.15',
        //         h => '2236.43',
        //         l => '2199.53',
        //         v => '12505.60574',
        //         n => 3381,
        //         q => '27682528.6655305',
        //         V => '6420.47929',
        //         Q => '14213680.1906424'
        //     }
        //
        return array(
            $this->safe_integer($ohlcv, 't'),
            $this->safe_number($ohlcv, 'o'),
            $this->safe_number($ohlcv, 'h'),
            $this->safe_number($ohlcv, 'l'),
            $this->safe_number($ohlcv, 'c'),
            $this->safe_number($ohlcv, 'v'),
        );
    }

